const SELECTED_PRODUCT = 'ERP';

const fs = require('fs');
const path = require('path');
const resultsDir = 'C:/Users/veeramani/.gemini/antigravity/scratch/Automation Workflow/temp_results';

// Cleanup previous results
if (fs.existsSync(resultsDir)) {
  const files = fs.readdirSync(resultsDir).filter(f => f.endsWith('.json'));
  for (const file of files) { try { fs.unlinkSync(path.join(resultsDir, file)); } catch (e) {} }
} else {
  fs.mkdirSync(resultsDir, { recursive: true });
}

const products = {
  'ERP': { product: 'ERP', folder: 'ERP' },
  'Camp': { product: 'Camp', folder: 'CampAccomodation' }
};

return [{ json: products[SELECTED_PRODUCT] }];

const fs = require('fs');
const items = $input.all();
const folder = items[0].json.folder;
const basePath = 'C:/Users/veeramani/desktop/playwright-mcp/tests';
const fullPath = `${basePath}/${folder}`;

// 🚀 RUN ALL SCRIPTS (No slice/limit)
const testFiles = fs.readdirSync(fullPath).filter(file => file.endsWith('.spec.js'));

return testFiles.map(file => ({ json: { ...items[0].json, filename: file, testPath: `tests/${folder}/${file}` } }));

const { execSync } = require('child_process');
const item = $input.item.json;
const cwd = 'C:/Users/veeramani/desktop/playwright-mcp';
const cmd = `npx playwright test "${item.testPath}" --reporter=json`;

const startTime = new Date();
let stdout = '', stderr = '', exitCode = 0;

try {
  stdout = execSync(cmd, { cwd, stdio: 'pipe', timeout: 300000 }).toString();
} catch (e) {
  exitCode = e.status || 1;
  stdout = (e.stdout || '').toString();
  stderr = (e.stderr || e.message || '').toString();
}

const endTime = new Date();
const duration = ((endTime - startTime) / 1000).toFixed(2);

let testCases = [], stats = { total: 0, passed: 0, failed: 0 }, reportSummary = '', screenshotPath = null;

try {
  const jsonMatch = stdout.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    const jsonData = JSON.parse(jsonMatch[0]);
    if (jsonData.stats) {
      stats.passed = jsonData.stats.expected || 0;
      stats.failed = jsonData.stats.unexpected || 0;
      stats.total = stats.passed + stats.failed;
    }
    if (jsonData.suites) {
      jsonData.suites.forEach(suite => {
        if (suite.specs) suite.specs.forEach(spec => {
          spec.tests.forEach(test => {
            const result = test.results && test.results[0];
            const attachments = result ? (result.attachments || []) : [];
            const screenshot = attachments.find(a => a.name === 'screenshot');
            if (screenshot && !screenshotPath) screenshotPath = screenshot.path;
            testCases.push({ title: spec.title, status: result ? result.status : 'unknown' });
          });
        });
      });
    }
    reportSummary = testCases.map(tc => `${tc.status === 'passed' ? '✅' : '❌'} ${tc.title}`).join('\n');
  }
} catch (e) {}

return {
  json: {
    ...item, exitCode, status: exitCode === 0 ? 'passed' : 'failed', duration: `${duration}s`, timestamp: new Date().toISOString(), stats,
    screenshotPath: (function() {
      if (!screenshotPath) return null;
      const isAbsolute = screenshotPath.includes(':') || screenshotPath.startsWith('/');
      return (isAbsolute ? screenshotPath : `${cwd}/${screenshotPath}`).replace(/\\/g, '/');
    })()
  }
};

